// node_conv_206 — pointwise (1x1) conv2d under tiled-streaming contract.
//   IC=256, OC=64, IH=IW=56, OH=OW=56, SH=SW=1, PH=PW=0
//   MP=4, channel_tile=32 -> IN_BEATS=8, OUT_BEATS=2 per pixel
// Per-pass cycles = 1 (ST_INIT) + 1024 (MP*K_TOTAL issues) + 2 (drain) + 3 (BIAS/SCALE/OUTPUT) = 1030
// Total latency = IN_BEATS + OC_PASSES*1030 = 8 + 16*1030 = 16488 cycles.
module node_conv_206 (
    input  wire              clk,
    input  wire              rst_n,
    input  wire              valid_in,
    output reg               ready_in,
    input  wire [255:0]      data_in,
    output reg               valid_out,
    output reg  [255:0]      data_out
);

    localparam integer IC            = 256;
    localparam integer OC            = 64;
    localparam integer OH            = 56;
    localparam integer OW            = 56;
    localparam integer K_TOTAL       = 256;
    localparam integer MP            = 4;
    localparam integer OC_PASSES     = 16;
    localparam integer CHANNEL_TILE  = 32;
    localparam integer IN_BEATS      = 8;
    localparam integer OUT_BEATS     = 2;
    localparam integer TILE_BITS     = 256;

    localparam integer SCALE_MULT    = 16865;
    localparam integer SCALE_SHIFT   = 20;

    localparam integer PROD_W        = 16;
    localparam integer ACC_W         = 24;
    localparam integer BIAS_W        = 32;
    localparam integer BIASED_W      = 33;
    localparam integer SCALE_CONST_W = 16;
    localparam integer SCALED_W      = 49;

    localparam signed [SCALE_CONST_W-1:0] SCALE_MULT_CONST = 16'sd16865;
    localparam signed [SCALED_W-1:0]      SCALE_ROUND_HALF =
        {{(SCALED_W-1){1'b0}}, 1'b1} <<< (SCALE_SHIFT - 1);
    localparam signed [SCALED_W-1:0]      SCALE_ROUND_HALF_M1 =
        SCALE_ROUND_HALF - {{(SCALED_W-1){1'b0}}, 1'b1};

    (* rom_style="block", ram_style="block" *) reg signed [7:0]  weights [0:OC*K_TOTAL-1];
    (* rom_style="block", ram_style="block" *) reg signed [31:0] biases  [0:OC-1];

    initial begin
        $readmemh("C:/Users/User/Desktop/RTL_LLM_CLAUDE/nn2rtl-repo/output/weights/node_conv_206_weights.hex", weights);
        $readmemh("C:/Users/User/Desktop/RTL_LLM_CLAUDE/nn2rtl-repo/output/weights/node_conv_206_bias.hex", biases);
    end

    localparam [2:0] ST_LOAD    = 3'd0;
    localparam [2:0] ST_INIT    = 3'd1;
    localparam [2:0] ST_RUNNING = 3'd2;
    localparam [2:0] ST_DRAIN   = 3'd3;
    localparam [2:0] ST_BIAS    = 3'd4;
    localparam [2:0] ST_SCALE   = 3'd5;
    localparam [2:0] ST_OUTPUT  = 3'd6;
    localparam [2:0] ST_EMIT    = 3'd7;

    reg [2:0] state;
    reg [3:0]        in_beat_idx;
    reg [IC*8-1:0]   in_latch;
    reg [5:0]        pixel_row;
    reg [5:0]        pixel_col;
    reg [12:0]       active_emit_count;
    reg [4:0]        oc_group;
    reg [1:0]        lane_counter;
    reg [8:0]        k_counter;
    reg [1:0]        drain_count;
    reg signed [ACC_W-1:0]    acc0, acc1, acc2, acc3;
    reg signed [BIASED_W-1:0] biased0, biased1, biased2, biased3;
    reg signed [SCALED_W-1:0] scaled0, scaled1, scaled2, scaled3;
    reg signed [7:0]                       weight_q;
    reg signed [7:0]                       in_q;
    (* use_dsp = "yes" *) reg signed [PROD_W-1:0] mul_q;
    reg [1:0]                              mac_lane_q1, mac_lane_q2;
    reg                                    mac_valid_q1, mac_valid_q2;
    reg [OC*8-1:0]   out_pack;
    reg [2:0]        out_beat_idx;
    reg signed [SCALED_W-1:0] v_tmp0, v_tmp1, v_tmp2, v_tmp3;
    reg signed [7:0]          sat_val0, sat_val1, sat_val2, sat_val3;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state <= ST_LOAD; ready_in <= 1'b1; valid_out <= 1'b0; data_out <= 256'd0;
            in_beat_idx <= 4'd0; in_latch <= {(IC*8){1'b0}};
            pixel_row <= 6'd0; pixel_col <= 6'd0; active_emit_count <= 13'd0;
            oc_group <= 5'd0; lane_counter <= 2'd0; k_counter <= 9'd0; drain_count <= 2'd0;
            weight_q <= 8'sd0; in_q <= 8'sd0; mul_q <= {PROD_W{1'b0}};
            mac_lane_q1 <= 2'd0; mac_lane_q2 <= 2'd0; mac_valid_q1 <= 1'b0; mac_valid_q2 <= 1'b0;
            out_pack <= {(OC*8){1'b0}}; out_beat_idx <= 3'd0;
            acc0 <= {ACC_W{1'b0}}; acc1 <= {ACC_W{1'b0}}; acc2 <= {ACC_W{1'b0}}; acc3 <= {ACC_W{1'b0}};
            biased0 <= {BIASED_W{1'b0}}; biased1 <= {BIASED_W{1'b0}}; biased2 <= {BIASED_W{1'b0}}; biased3 <= {BIASED_W{1'b0}};
            scaled0 <= {SCALED_W{1'b0}}; scaled1 <= {SCALED_W{1'b0}}; scaled2 <= {SCALED_W{1'b0}}; scaled3 <= {SCALED_W{1'b0}};
        end else begin
            mul_q <= $signed(weight_q) * $signed(in_q);
            mac_lane_q2 <= mac_lane_q1;
            mac_valid_q2 <= mac_valid_q1;
            mac_valid_q1 <= 1'b0;
            if (mac_valid_q2) begin
                case (mac_lane_q2)
                    2'd0: acc0 <= acc0 + $signed(mul_q);
                    2'd1: acc1 <= acc1 + $signed(mul_q);
                    2'd2: acc2 <= acc2 + $signed(mul_q);
                    2'd3: acc3 <= acc3 + $signed(mul_q);
                endcase
            end
            case (state)
                ST_LOAD: begin
                    valid_out <= 1'b0;
                    if (valid_in && ready_in) begin
                        in_latch[in_beat_idx*TILE_BITS +: TILE_BITS] <= data_in;
                        if (in_beat_idx == IN_BEATS - 1) begin
                            in_beat_idx <= 4'd0; ready_in <= 1'b0; oc_group <= 5'd0; state <= ST_INIT;
                        end else in_beat_idx <= in_beat_idx + 4'd1;
                    end
                end
                ST_INIT: begin
                    acc0 <= {ACC_W{1'b0}}; acc1 <= {ACC_W{1'b0}}; acc2 <= {ACC_W{1'b0}}; acc3 <= {ACC_W{1'b0}};
                    k_counter <= 9'd0; lane_counter <= 2'd0; drain_count <= 2'd0; state <= ST_RUNNING;
                end
                ST_RUNNING: begin
                    weight_q <= weights[(oc_group*MP + lane_counter)*K_TOTAL + k_counter];
                    in_q <= in_latch[k_counter*8 +: 8];
                    mac_lane_q1 <= lane_counter; mac_valid_q1 <= 1'b1;
                    if (lane_counter == MP - 1) begin
                        lane_counter <= 2'd0;
                        if (k_counter == K_TOTAL - 1) begin
                            k_counter <= 9'd0; drain_count <= 2'd0; state <= ST_DRAIN;
                        end else k_counter <= k_counter + 9'd1;
                    end else lane_counter <= lane_counter + 2'd1;
                end
                ST_DRAIN: begin
                    if (drain_count == 2'd1) begin drain_count <= 2'd0; state <= ST_BIAS; end
                    else drain_count <= drain_count + 2'd1;
                end
                ST_BIAS: begin
                    biased0 <= $signed(acc0) + $signed(biases[oc_group*MP + 0]);
                    biased1 <= $signed(acc1) + $signed(biases[oc_group*MP + 1]);
                    biased2 <= $signed(acc2) + $signed(biases[oc_group*MP + 2]);
                    biased3 <= $signed(acc3) + $signed(biases[oc_group*MP + 3]);
                    state <= ST_SCALE;
                end
                ST_SCALE: begin
                    scaled0 <= $signed(biased0) * $signed(SCALE_MULT_CONST);
                    scaled1 <= $signed(biased1) * $signed(SCALE_MULT_CONST);
                    scaled2 <= $signed(biased2) * $signed(SCALE_MULT_CONST);
                    scaled3 <= $signed(biased3) * $signed(SCALE_MULT_CONST);
                    state <= ST_OUTPUT;
                end
                ST_OUTPUT: begin
                    v_tmp0 = (scaled0 + (scaled0[SCALED_W-1] ? SCALE_ROUND_HALF_M1 : SCALE_ROUND_HALF)) >>> SCALE_SHIFT;
                    v_tmp1 = (scaled1 + (scaled1[SCALED_W-1] ? SCALE_ROUND_HALF_M1 : SCALE_ROUND_HALF)) >>> SCALE_SHIFT;
                    v_tmp2 = (scaled2 + (scaled2[SCALED_W-1] ? SCALE_ROUND_HALF_M1 : SCALE_ROUND_HALF)) >>> SCALE_SHIFT;
                    v_tmp3 = (scaled3 + (scaled3[SCALED_W-1] ? SCALE_ROUND_HALF_M1 : SCALE_ROUND_HALF)) >>> SCALE_SHIFT;
                    sat_val0 = (v_tmp0 > 127) ? 8'sd127 : (v_tmp0 < -128) ? -8'sd128 : v_tmp0[7:0];
                    sat_val1 = (v_tmp1 > 127) ? 8'sd127 : (v_tmp1 < -128) ? -8'sd128 : v_tmp1[7:0];
                    sat_val2 = (v_tmp2 > 127) ? 8'sd127 : (v_tmp2 < -128) ? -8'sd128 : v_tmp2[7:0];
                    sat_val3 = (v_tmp3 > 127) ? 8'sd127 : (v_tmp3 < -128) ? -8'sd128 : v_tmp3[7:0];
                    out_pack[(oc_group*MP + 0)*8 +: 8] <= sat_val0;
                    out_pack[(oc_group*MP + 1)*8 +: 8] <= sat_val1;
                    out_pack[(oc_group*MP + 2)*8 +: 8] <= sat_val2;
                    out_pack[(oc_group*MP + 3)*8 +: 8] <= sat_val3;
                    if (oc_group == OC_PASSES - 1) begin
                        valid_out <= 1'b1; data_out <= out_pack[0 +: TILE_BITS];
                        out_beat_idx <= 3'd1; state <= ST_EMIT;
                    end else begin oc_group <= oc_group + 5'd1; state <= ST_INIT; end
                end
                ST_EMIT: begin
                    if (out_beat_idx == OUT_BEATS[2:0]) begin
                        valid_out <= 1'b0; ready_in <= 1'b1; state <= ST_LOAD;
                        out_beat_idx <= 3'd0; oc_group <= 5'd0;
                        if (active_emit_count == OH*OW - 1) begin
                            active_emit_count <= 13'd0; pixel_row <= 6'd0; pixel_col <= 6'd0;
                        end else begin
                            active_emit_count <= active_emit_count + 13'd1;
                            if (pixel_col == OW - 1) begin pixel_col <= 6'd0; pixel_row <= pixel_row + 6'd1; end
                            else pixel_col <= pixel_col + 6'd1;
                        end
                    end else begin
                        data_out <= out_pack[out_beat_idx*TILE_BITS +: TILE_BITS];
                        valid_out <= 1'b1; out_beat_idx <= out_beat_idx + 3'd1;
                    end
                end
                default: state <= ST_LOAD;
            endcase
        end
    end
endmodule
